package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetName() throws Exception {
    String expectedName = "Test Item";

    // Use reflection to create an instance of LineItem since constructor details are incomplete
    Class<?> clazz = Class.forName("com.google.gson.examples.android.model.LineItem");
    var constructor = clazz.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance(expectedName, 5, 1000L, "USD");

    var getNameMethod = clazz.getDeclaredMethod("getName");
    getNameMethod.setAccessible(true);
    String actualName = (String) getNameMethod.invoke(lineItem);

    assertEquals(expectedName, actualName);
  }
}
